export enum SiteCategory {
  UNESCO = 'UNESCO Heritage',
  HINDU = 'Hindu Temple',
  BUDDHIST = 'Buddhist',
  PALACE = 'Palace/Fort',
  RELIGIOUS = 'Religious Site',
  NATURAL = 'Natural/Religious',
  ARCHAEOLOGICAL = 'Archaeological'
}

export interface HeritageSite {
  id: string;
  name: string;
  location: string;
  type: string;
  latitude: number;
  longitude: number;
  significance: string;
  imageUrl: string;
  categories: SiteCategory[];
}

export interface MapSettings {
  center: [number, number];
  zoom: number;
  tileLayer: string;
}

import { HeritageSite, SiteCategory } from '../types';
import { RAW_CSV_DATA } from '../constants';

export const parseHeritageData = (): HeritageSite[] => {
  const lines = RAW_CSV_DATA.split('\n');
  const headers = lines[0].split(',');

  return lines.slice(1).map((line, index) => {
    // Handling possible comma within significance if needed, but the provided CSV is simple
    const values = line.split(',');
    const typeStr = values[2] || '';

    // Logic to determine categories based on Type string
    const categories: SiteCategory[] = [];
    const normalizedType = typeStr.toLowerCase();

    if (normalizedType.includes('unesco')) categories.push(SiteCategory.UNESCO);
    if (normalizedType.includes('hindu')) categories.push(SiteCategory.HINDU);
    if (normalizedType.includes('buddhist') || normalizedType.includes('stupa') || normalizedType.includes('monastery')) categories.push(SiteCategory.BUDDHIST);
    if (normalizedType.includes('palace') || normalizedType.includes('fort') || normalizedType.includes('museum')) categories.push(SiteCategory.PALACE);
    if (normalizedType.includes('religious') || normalizedType.includes('cave') || normalizedType.includes('hill')) categories.push(SiteCategory.RELIGIOUS);
    if (normalizedType.includes('natural')) categories.push(SiteCategory.NATURAL);
    if (normalizedType.includes('archaeological')) categories.push(SiteCategory.ARCHAEOLOGICAL);

    // Fallback if no category matches
    if (categories.length === 0) categories.push(SiteCategory.RELIGIOUS);

    return {
      id: `site-${index}`,
      name: values[0],
      location: values[1],
      type: typeStr,
      latitude: parseFloat(values[3]),
      longitude: parseFloat(values[4]),
      significance: values[5],
      imageUrl: `https://picsum.photos/seed/${encodeURIComponent(values[0])}/400/250`,
      categories
    };
  });
};

import L from 'leaflet';
import { HeritageSite, SiteCategory } from '../types';
import { CATEGORY_COLORS } from '../constants';

export const createCustomIcon = (site: HeritageSite) => {
  const categories = site.categories;
  const primaryColor = CATEGORY_COLORS[categories[0]] || '#333';
  const secondaryColor = categories.length > 1 ? CATEGORY_COLORS[categories[1]] : primaryColor;

  const isUnesco = categories.includes(SiteCategory.UNESCO);

  const html = `
    <div class="relative group">
      <div class="w-8 h-8 rounded-full border-2 border-white shadow-lg flex items-center justify-center overflow-hidden transition-transform duration-300 group-hover:scale-125" 
           style="background: linear-gradient(135deg, ${primaryColor} 50%, ${secondaryColor} 50%);">
        ${isUnesco ? `
          <div class="w-4 h-4 bg-white rounded-full flex items-center justify-center">
            <svg class="w-3 h-3 text-yellow-600" fill="currentColor" viewBox="0 0 20 20">
              <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
            </svg>
          </div>
        ` : ''}
      </div>
      <div class="absolute -bottom-1 left-1/2 -translate-x-1/2 w-2 h-2 bg-white rotate-45 shadow-sm border-b border-r border-gray-200"></div>
    </div>
  `;

  return L.divIcon({
    html,
    className: 'custom-heritage-marker',
    iconSize: [32, 32],
    iconAnchor: [16, 32],
    popupAnchor: [0, -32]
  });
};

