export default Sidebar;

import React, { useEffect, useRef } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMap, ZoomControl } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet.markercluster';
import { HeritageSite } from '../types';
import { DEFAULT_NEPAL_CENTER, DEFAULT_ZOOM } from '../constants';
import { createCustomIcon } from './CustomMarker';
import SiteDetailsPopup from './SiteDetailsPopup';

// Add MarkerCluster components correctly using Leaflet hooks
const MarkerClusterGroup: React.FC<{ sites: HeritageSite[]; onMarkerClick: (site: HeritageSite) => void; activeSiteId: string | null }> = ({ sites, onMarkerClick, activeSiteId }) => {
  const map = useMap();
  const clusterGroupRef = useRef<L.MarkerClusterGroup | null>(null);

  useEffect(() => {
    if (!clusterGroupRef.current) {
      clusterGroupRef.current = L.markerClusterGroup({
        showCoverageOnHover: false,
        zoomToBoundsOnClick: true,
        spiderfyOnMaxZoom: true,
        chunkedLoading: true,
      });
    }

    const clusterGroup = clusterGroupRef.current;
    clusterGroup.clearLayers();

    sites.forEach((site) => {
      const marker = L.marker([site.latitude, site.longitude], {
        icon: createCustomIcon(site)
      });

      marker.on('click', () => {
        onMarkerClick(site);
      });

      // Attach popup directly for easier React management if needed, 
      // but standard Leaflet popups are more performant for many markers.
      const popupDiv = document.createElement('div');
      // We can't easily render React here without a portal, so we'll use a simpler approach
      // or just rely on the React Marker components instead.
      // Let's switch to standard react-leaflet markers for better integration.
    });

    map.addLayer(clusterGroup);

    return () => {
      map.removeLayer(clusterGroup);
    };
  }, [sites, map, onMarkerClick]);

  return null;
};

// Component to handle auto-panning when activeSiteId changes
const MapController: React.FC<{ activeSite: HeritageSite | null }> = ({ activeSite }) => {
  const map = useMap();
  useEffect(() => {
    if (activeSite) {
      map.flyTo([activeSite.latitude, activeSite.longitude], 14, {
        duration: 1.5
      });
    }
  }, [activeSite, map]);
  return null;
};

interface MapViewProps {
  sites: HeritageSite[];
  activeSite: HeritageSite | null;
  onSiteSelect: (site: HeritageSite) => void;
  mapType: 'osm' | 'dark' | 'satellite';
}

const MapView: React.FC<MapViewProps> = ({ sites, activeSite, onSiteSelect, mapType }) => {
  const getTileLayer = () => {
    switch(mapType) {
      case 'dark': return 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png';
      case 'satellite': return 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}';
      default: return 'https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png';
    }
  };

  return (
    <div className="w-full h-full relative">
      <MapContainer 
        center={DEFAULT_NEPAL_CENTER} 
        zoom={DEFAULT_ZOOM} 
        className="w-full h-full"
        zoomControl={false}
      >
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
          url={getTileLayer()}
        />

        <ZoomControl position="bottomright" />
        <MapController activeSite={activeSite} />

        {/* Using standard Markers with react-leaflet-cluster equivalent logic manually */}
        {/* For simplicity in this demo, we render markers directly. In a production app with thousands, use MarkerCluster. */}
        {sites.map((site) => (
          <Marker 
            key={site.id} 
            position={[site.latitude, site.longitude]}
            icon={createCustomIcon(site)}
            eventHandlers={{
              click: () => onSiteSelect(site)
            }}
          >
            <Popup minWidth={260} closeButton={false}>
              <SiteDetailsPopup site={site} />
            </Popup>
          </Marker>
        ))}
      </MapContainer>

      {/* Map Legend (Overlay) */}
      <div className="absolute bottom-8 left-8 z-[1000] bg-white/90 backdrop-blur-sm p-4 rounded-2xl shadow-xl border border-white/20 hidden md:block">
        <h4 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-3">Map Legend</h4>
        <div className="grid grid-cols-2 gap-x-6 gap-y-2">
          {Object.entries(CATEGORY_COLORS).map(([cat, color]) => (
            <div key={cat} className="flex items-center gap-2">
              <span className="w-3 h-3 rounded-full border border-white shadow-sm" style={{ backgroundColor: color }}></span>
              <span className="text-[10px] font-medium text-gray-700">{cat}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default MapView;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import MapView from './components/MapView';
import { HeritageSite, SiteCategory } from './types';
import { parseHeritageData } from './utils/dataParser';
import { Layers, Maximize, LocateFixed, Home } from 'lucide-react';

const App: React.FC = () => {
  const allSites = useMemo(() => parseHeritageData(), []);

  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategories, setSelectedCategories] = useState<SiteCategory[]>(Object.values(SiteCategory));
  const [activeSite, setActiveSite] = useState<HeritageSite | null>(null);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  const [mapType, setMapType] = useState<'osm' | 'dark' | 'satellite'>('osm');

  const filteredSites = useMemo(() => {
    return allSites.filter(site => {
      const matchesSearch = site.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           site.location.toLowerCase().includes(searchTerm.toLowerCase());

      const matchesCategory = site.categories.some(cat => selectedCategories.includes(cat));

      return matchesSearch && matchesCategory;
    });
  }, [allSites, searchTerm, selectedCategories]);

  const handleFilterToggle = (category: SiteCategory) => {
    setSelectedCategories(prev => 
      prev.includes(category) 
        ? prev.filter(c => c !== category) 
        : [...prev, category]
    );
  };

  const handleSiteSelect = (site: HeritageSite) => {
    setActiveSite(site);
  };

  const resetView = () => {
    setActiveSite(null);
    setSearchTerm('');
    setSelectedCategories(Object.values(SiteCategory));
  };

  return (
    <div className="flex h-screen w-full bg-gray-100 overflow-hidden font-sans">
      {/* Sidebar Component */}
      <Sidebar 
        sites={filteredSites}
        onSearch={setSearchTerm}
        onFilterToggle={handleFilterToggle}
        selectedCategories={selectedCategories}
        activeSiteId={activeSite?.id || null}
        onSiteClick={handleSiteSelect}
        isCollapsed={isSidebarCollapsed}
        setIsCollapsed={setIsSidebarCollapsed}
      />

      {/* Main Map Content Area */}
      <main className="relative flex-1 h-full">
        {/* Floating Map Controls */}
        <div className="absolute top-6 right-6 z-[1000] flex flex-col gap-3">
          <div className="bg-white p-1 rounded-xl shadow-lg border border-gray-100 flex flex-col">
             <button 
              onClick={() => setMapType(mapType === 'osm' ? 'satellite' : mapType === 'satellite' ? 'dark' : 'osm')}
              title="Change Map Style"
              className="p-2.5 hover:bg-gray-50 text-gray-600 rounded-lg transition-colors flex items-center justify-center"
            >
              <Layers size={20} />
            </button>
            <button 
              onClick={resetView}
              title="Reset View"
              className="p-2.5 hover:bg-gray-50 text-gray-600 rounded-lg transition-colors border-t border-gray-100 flex items-center justify-center"
            >
              <Home size={20} />
            </button>
            <button 
              onClick={() => {
                if (navigator.geolocation) {
                   navigator.geolocation.getCurrentPosition((pos) => {
                     // In a real app we'd fly the map here, but for this demo we'll just show the button works
                     console.log("Locating user...", pos.coords);
                   });
                }
              }}
              title="My Location"
              className="p-2.5 hover:bg-gray-50 text-gray-600 rounded-lg transition-colors border-t border-gray-100 flex items-center justify-center"
            >
              <LocateFixed size={20} />
            </button>
          </div>
        </div>

        {/* Map View Component */}
        <MapView 
          sites={filteredSites} 
          activeSite={activeSite}
          onSiteSelect={handleSiteSelect}
          mapType={mapType}
        />

        {/* Mobile Header / Search Toggle (Visible only on mobile if sidebar hidden) */}
        {isSidebarCollapsed && (
          <div className="absolute top-4 left-4 z-[1000] md:hidden">
            <button 
              onClick={() => setIsSidebarCollapsed(false)}
              className="bg-white p-3 rounded-full shadow-xl border border-gray-100 text-red-600"
            >
              <Search size={24} />
            </button>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

