/**
 * Returns an SVG path string for the relevant category icon.
 */
const getCategoryIconPath = (category: SiteCategory): string => {
  switch (category) {
    case SiteCategory.UNESCO:
      // Star/Award Icon
      return '<path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"></path>';
    case SiteCategory.HINDU:
      // Temple Shikhara style (Tower)
      return '<path d="M12 2L4 10v10h16V10l-8-8zm0 4l4 4H8l4-4zm-4 12v-6h8v6H8z"></path>';
    case SiteCategory.BUDDHIST:
      // Stupa/Monastery dome style
      return '<path d="M12 2a8 8 0 0 0-8 8v2h16v-2a8 8 0 0 0-8-8zm0 2a6 6 0 0 1 6 6H6a6 6 0 0 1 6-6zm-7 10h14v2H5v-2zm2 4h10v2H7v-2z"></path>';
    case SiteCategory.PALACE:
      // Fort/Palace (Castle-like)
      return '<path d="M21 20v-9l-4-4l-4 4v9m-4 0v-9l-4-4l-4 4v9m16 0h-16m4-11V3m8 6V3"></path>';
    case SiteCategory.RELIGIOUS:
      // Prayer/Shrine
      return '<path d="M12 3v3m0 12v3M5.6 5.6l2.1 2.1m8.6 8.6l2.1 2.1M3 12h3m12 0h3M5.6 18.4l2.1-2.1m8.6-8.6l2.1-2.1"></path>';
    case SiteCategory.NATURAL:
      // Mountain/Nature
      return '<path d="M8 20l4-9l4 9m-11 0l5-13l5 13"></path>';
    case SiteCategory.ARCHAEOLOGICAL:
      // Ancient Pillar/Ruins
      return '<path d="M5 20h14M8 20v-6a2 2 0 0 1 4 0v6m4 0v-10a2 2 0 0 0-4 0v10"></path>';
    default:
      // Default pin
      return '<path d="M12 21s-7-7.5-7-11.5a7 7 0 1 1 14 0c0 4-7 11.5-7 11.5z"></path>';
  }
};

export const createCustomIcon = (site: HeritageSite) => {
  const categories = site.categories;
  const primaryCategory = categories[0];
  const primaryColor = CATEGORY_COLORS[primaryCategory] || '#333';
  const secondaryColor = categories.length > 1 ? CATEGORY_COLORS[categories[1]] : primaryColor;

  // Decide which icon to show. UNESCO takes priority, then the primary category.
  const iconCategory = categories.includes(SiteCategory.UNESCO) ? SiteCategory.UNESCO : primaryCategory;
  const iconSvgPath = getCategoryIconPath(iconCategory);

  const html = `
    <div class="relative group">
      <div class="w-10 h-10 rounded-full border-2 border-white shadow-xl flex items-center justify-center overflow-hidden transition-all duration-300 group-hover:scale-125 group-hover:rotate-3" 
           style="background: linear-gradient(135deg, ${primaryColor} 50%, ${secondaryColor} 50%);">
        <svg viewBox="0 0 24 24" class="w-6 h-6 text-white drop-shadow-md" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
          ${iconSvgPath}
        </svg>
      </div>
      <!-- Triangle pointer -->
      <div class="absolute -bottom-1 left-1/2 -translate-x-1/2 w-3 h-3 bg-white rotate-45 shadow-sm border-b border-r border-gray-100"></div>

      <!-- Hover Tooltip -->
      <div class="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 px-2 py-1 bg-gray-900 text-white text-[10px] rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none z-10">
        ${site.name}
      </div>
    </div>
  `;

  return L.divIcon({
    html,
    className: 'custom-heritage-marker',
    iconSize: [40, 40],
    iconAnchor: [20, 40],
    popupAnchor: [0, -40]
  });
};

