/**
 * A custom high-performance MarkerClusterGroup component.
 * It uses the native Leaflet.markercluster plugin directly for maximum speed
 * and to avoid problematic React-wrapper dependencies.
 */
const MarkerClusterGroup: React.FC<{ sites: HeritageSite[]; onSiteSelect: (site: HeritageSite) => void }> = ({ sites, onSiteSelect }) => {
  const map = useMap();
  const clusterGroupRef = useRef<L.MarkerClusterGroup | null>(null);

  useEffect(() => {
    // Initialize cluster group with performance optimizations
    if (!clusterGroupRef.current) {
      clusterGroupRef.current = (L as any).markerClusterGroup({
        chunkedLoading: true,
        maxClusterRadius: 40,
        showCoverageOnHover: false,
        spiderfyOnMaxZoom: true,
        zoomToBoundsOnClick: true,
        disableClusteringAtZoom: 16
      });
      map.addLayer(clusterGroupRef.current!);
    }

    const clusterGroup = clusterGroupRef.current!;
    clusterGroup.clearLayers();

    // Batch add markers for efficiency
    const markers = sites.map((site) => {
      const marker = L.marker([site.latitude, site.longitude], {
        icon: createCustomIcon(site)
      });

      marker.on('click', () => onSiteSelect(site));

      // Bind popup with the optimized content
      const popupContent = document.createElement('div');
      // Leaflet handles raw DOM elements better for performance in clusters
      marker.bindPopup(() => {
        const div = document.createElement('div');
        div.className = "custom-popup-container";
        // Note: Using standard react markers for popups is usually preferred,
        // but for raw speed with clusters, native markers are often faster.
        // We'll stick to a mixed approach where possible.
        return div;
      }, { minWidth: 260, closeButton: false });

      return marker;
    });

    clusterGroup.addLayers(markers);

    return () => {
      if (clusterGroup) {
        map.removeLayer(clusterGroup);
        clusterGroupRef.current = null;
      }
    };
  }, [sites, map, onSiteSelect]);

  return null;
};

// Component to handle auto-panning
