export const createCustomIcon = (site: HeritageSite) => {
  const categories = site.categories;
  const primaryCategory = categories[0];
  const primaryColor = CATEGORY_COLORS[primaryCategory] || '#333';
  const secondaryColor = categories.length > 1 ? CATEGORY_COLORS[categories[1]] : primaryColor;

  const iconCategory = categories.includes(SiteCategory.UNESCO) ? SiteCategory.UNESCO : primaryCategory;
  const iconSvgPath = getCategoryIconPath(iconCategory);

  const html = `
    <div style="position: relative; display: flex; align-items: center; justify-content: center; width: 40px; height: 40px;">
      <div style="
        width: 36px; 
        height: 36px; 
        border-radius: 50%; 
        border: 2px solid white; 
        box-shadow: 0 4px 10px rgba(0,0,0,0.3);
        display: flex; 
        align-items: center; 
        justify-content: center; 
        overflow: hidden;
        background: linear-gradient(135deg, ${primaryColor} 50%, ${secondaryColor} 50%);
      ">
        <svg viewBox="0 0 24 24" style="width: 22px; height: 22px; color: white;" fill="currentColor">
          ${iconSvgPath}
        </svg>
      </div>
      <div style="
        position: absolute; 
        bottom: -4px; 
        left: 50%; 
        transform: translateX(-50%) rotate(45deg); 
        width: 10px; 
        height: 10px; 
        background: white; 
        box-shadow: 2px 2px 2px rgba(0,0,0,0.1);
      "></div>
    </div>
  `;

  return L.divIcon({
    html,
    className: 'custom-heritage-marker-container',
    iconSize: [40, 40],
    iconAnchor: [20, 40],
    popupAnchor: [0, -35]
  });
};

