/**
 * Returns a high-quality SVG path for heritage categories.
 */
const getCategoryIconPath = (category: SiteCategory): string => {
  switch (category) {
    case SiteCategory.UNESCO:
      return '<path d="M4 22h16v-2H4v2zM2 6v2h20V6H2zm2 12h2v-8H4v8zm5 0h2v-8H9v8zm5 0h2v-8h-2v8zm5 0h2v-8h-2v8zM2 2v2h20V2H2z"/>';
    case SiteCategory.HINDU:
      return '<path d="M12 2L4 7h16L12 2zM12 7l-7 5h14l-7-5zM12 12l-8 5h16l-8-5zM5 17v3h14v-3H5z"/>';
    case SiteCategory.BUDDHIST:
      return '<path d="M12 2c-1 0-2 1-2 2h4c0-1-1-2-2-2zM7 12c0-3 2-5 5-5s5 2 5 5v2H7v-2zM5 16h14v2H5v-2zM4 20h16v2H4v-2z"/>';
    case SiteCategory.PALACE:
      return '<path d="M3 21h18v-2h-1V9l-4-4-4 4v10H10V9L6 5 2 9v10H1V21z"/>';
    case SiteCategory.RELIGIOUS:
      return '<path d="M12 2C12 2 7 7 7 12s5 10 5 10s5-5 5-10s-5-10-5-10zm0 16c-3.3 0-6-2.7-6-6s6-10 6-10s6 6.7 6 10s-2.7 6-6 6z"/>';
    case SiteCategory.NATURAL:
      return '<path d="M14 10l-4 6l-3-2l-5 7h20zM22 21h-20v-2l5-7l3 2l4-6l5 6v7z"/>';
    case SiteCategory.ARCHAEOLOGICAL:
      return '<path d="M6 5h12v2H6V5zm3 14h6v-10H9v10zm-5 2h16v-2H4v2z"/>';
    default:
      return '<path d="M12 2L2 22h20L12 2z"/>';
  }
};

export const createCustomIcon = (site: HeritageSite) => {
  const categories = site.categories;
  const primaryCategory = categories[0];
  const primaryColor = CATEGORY_COLORS[primaryCategory] || '#333';
  const secondaryColor = categories.length > 1 ? CATEGORY_COLORS[categories[1]] : primaryColor;

  const iconCategory = categories.includes(SiteCategory.UNESCO) ? SiteCategory.UNESCO : primaryCategory;
  const iconSvgPath = getCategoryIconPath(iconCategory);

  const html = `
    <div style="position: relative; display: flex; align-items: center; justify-content: center; width: 44px; height: 44px; margin-top: -10px;">
      <div style="
        width: 38px; 
        height: 38px; 
        border-radius: 50%; 
        border: 2px solid white; 
        box-shadow: 0 5px 15px rgba(0,0,0,0.4);
        display: flex; 
        align-items: center; 
        justify-content: center; 
        background: linear-gradient(135deg, ${primaryColor} 0%, ${secondaryColor} 100%);
        z-index: 2;
      ">
        <svg viewBox="0 0 24 24" style="width: 22px; height: 22px; color: white;" fill="currentColor">
          ${iconSvgPath}
        </svg>
      </div>
      <div style="
        position: absolute; 
        bottom: 0px; 
        left: 50%; 
        transform: translateX(-50%) rotate(45deg); 
        width: 14px; 
        height: 14px; 
        background: ${secondaryColor}; 
        border-right: 2px solid white;
        border-bottom: 2px solid white;
        z-index: 1;
      "></div>
    </div>
  `;

  return L.divIcon({
    html,
    className: 'custom-heritage-marker-container',
    iconSize: [44, 44],
    iconAnchor: [22, 44],
    popupAnchor: [0, -40]
  });
};

