            <div key={cat} className="flex items-center gap-3">
              <div 
                className="w-6 h-6 rounded-lg flex items-center justify-center shadow-sm border border-white"
                style={{ backgroundColor: color }}
              >
                <LegendIcon category={cat as SiteCategory} />
