import React, { useEffect, useRef, useState } from 'react';
import { MapContainer, TileLayer, useMap, ZoomControl, GeoJSON, useMapEvents, Marker, Tooltip } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet.markercluster';
import { createRoot } from 'react-dom/client';
import { HeritageSite, SiteCategory } from '../types';
import { DEFAULT_NEPAL_CENTER, DEFAULT_ZOOM, CATEGORY_COLORS } from '../constants';
import { createCustomIcon } from './CustomMarker';
import SiteDetailsPopup from './SiteDetailsPopup';

// Marker Clustering Component - Customized to match user reference
const MarkerClusterGroup: React.FC<{ 
  sites: HeritageSite[]; 
  activeSite: HeritageSite | null;
  onSiteSelect: (site: HeritageSite) => void 
}> = ({ sites, activeSite, onSiteSelect }) => {
  const map = useMap();
  const clusterGroupRef = useRef<any>(null);
  const markerMapRef = useRef<Map<string, L.Marker>>(new Map());

  useEffect(() => {
    if (!clusterGroupRef.current) {
      clusterGroupRef.current = (L as any).markerClusterGroup({
        chunkedLoading: true,
        maxClusterRadius: 50,
        showCoverageOnHover: false,
        spiderfyOnMaxZoom: true,
        disableClusteringAtZoom: 16,
        // Custom cluster icons matching the user's reference
        iconCreateFunction: (cluster: any) => {
          const count = cluster.getChildCount();
          return L.divIcon({
            html: `
              <div class="flex items-center justify-center">
                <div class="relative w-12 h-12 flex items-center justify-center bg-[#2d9a91] text-white font-black rounded-full border-4 border-[#e3ded0] shadow-xl">
                  ${count}
                </div>
              </div>
            `,
            className: 'custom-cluster-icon',
            iconSize: L.point(48, 48)
          });
        },
        polygonOptions: {
          fillColor: '#2d9a91',
          color: '#2d9a91',
          weight: 2,
          opacity: 0.3,
          fillOpacity: 0.05
        }
      });
      map.addLayer(clusterGroupRef.current!);
    }

    const clusterGroup = clusterGroupRef.current!;
    clusterGroup.clearLayers();
    markerMapRef.current.clear();

    const markers = sites.map((site) => {
      const marker = L.marker([site.latitude, site.longitude], {
        icon: createCustomIcon(site)
      });

      marker.on('click', () => {
        onSiteSelect(site);
      });

      const container = document.createElement('div');
      const root = createRoot(container);
      root.render(<SiteDetailsPopup site={site} />);

      marker.bindPopup(container, { 
        minWidth: 280, 
        closeButton: false,
        offset: [0, -10]
      });

      markerMapRef.current.set(site.id, marker);
      return marker;
    });

    clusterGroup.addLayers(markers);

    return () => {
      if (clusterGroup && map.hasLayer(clusterGroup)) {
        map.removeLayer(clusterGroup);
      }
      clusterGroupRef.current = null;
    };
  }, [sites, map, onSiteSelect]);

  useEffect(() => {
    if (activeSite && markerMapRef.current.has(activeSite.id)) {
      const marker = markerMapRef.current.get(activeSite.id)!;
      map.flyTo([activeSite.latitude, activeSite.longitude], 15, { duration: 1.5 });
      setTimeout(() => marker.openPopup(), 1600);
    }
  }, [activeSite, map]);

  return null;
};

// Admin Boundary Handler with Labels
const AdminBoundaries: React.FC = () => {
  const [zoom, setZoom] = useState(DEFAULT_ZOOM);
  const [provinceData, setProvinceData] = useState<any>(null);
  const [districtData, setDistrictData] = useState<any>(null);

  useMapEvents({
    zoomend: (e) => {
      setZoom(e.target.getZoom());
    }
  });

  useEffect(() => {
    // Fetch Province GeoJSON
    fetch('https://raw.githubusercontent.com/nepal-maps/nepal-maps.github.io/master/geojson/province.json')
      .then(res => res.json())
      .then(data => setProvinceData(data))
      .catch(() => {});

    // Fetch District GeoJSON
    fetch('https://raw.githubusercontent.com/nepal-maps/nepal-maps.github.io/master/geojson/district.json')
      .then(res => res.json())
      .then(data => setDistrictData(data))
      .catch(() => {});
  }, []);

  const provinceStyle = {
    color: '#000000',
    weight: 2.5,
    opacity: 1,
    fillOpacity: 0.02,
    dashArray: '5, 10'
  };

  const districtStyle = {
    color: '#000000',
    weight: 1.2,
    opacity: 0.8,
    fillOpacity: 0,
    dashArray: '3, 6'
  };

  // Helper to find polygon centroid for labels
  const getCentroid = (feature: any) => {
    const layer = L.geoJSON(feature);
    const bounds = layer.getBounds();
    return bounds.getCenter();
  };

  return (
    <>
      {provinceData && zoom < 9 && (
        <>
          <GeoJSON data={provinceData} style={provinceStyle} interactive={false} />
          {provinceData.features.map((feature: any, idx: number) => (
            <Marker 
              key={`prov-label-${idx}`}
              position={getCentroid(feature)}
              icon={L.divIcon({
                html: `<div class="text-[10px] font-black text-gray-700 uppercase tracking-tighter bg-white/40 px-1 rounded shadow-sm">Province ${feature.properties.province || feature.properties.PROVINCE || idx + 1}</div>`,
                className: 'admin-label',
                iconSize: [80, 20],
                iconAnchor: [40, -10]
              })}
              interactive={false}
            />
          ))}
        </>
      )}
      {districtData && zoom >= 9 && (
        <>
          <GeoJSON data={districtData} style={districtStyle} interactive={false} />
          {zoom >= 10 && districtData.features.map((feature: any, idx: number) => (
            <Marker 
              key={`dist-label-${idx}`}
              position={getCentroid(feature)}
              icon={L.divIcon({
                html: `<div class="text-[8px] font-bold text-gray-500 uppercase tracking-wider">${feature.properties.DISTRICT || feature.properties.name || ''}</div>`,
                className: 'admin-label',
                iconSize: [60, 20]
              })}
              interactive={false}
            />
          ))}
        </>
      )}
    </>
  );
};

