  HINDU = 'Hindu Temple',
  BUDDHIST = 'Buddhist',
  PALACE = 'Palace/Fort',
  RELIGIOUS = 'Religious Site',
  NATURAL = 'Natural/Religious',
  ARCHAEOLOGICAL = 'Archaeological'
}

export interface HeritageSite {
  id: string;
  name: string;
  location: string;
  type: string;
  latitude: number;
  longitude: number;
  significance: string;
  imageUrl: string;
  images: string[];
  historicalBackground: string;
  culturalImportance: string;
  architecture: string;
  era: string;
  unescoStatus: boolean;
  bestTime: string;
  legend?: string;
