import { HeritageSite, SiteCategory } from '../types';
import { RAW_CSV_DATA } from '../constants';

const SKETCHFAB_MAP: Record<string, string> = {
  'Kathmandu Durbar Square': '804928d39c0d4530869680a65600c62c',
  'Pashupatinath Temple': 'd1dbd0e3109548f3a99ae4a2eca1493b',
  'Boudhanath Stupa': '6be545b7367c42b083b708461775d787',
  'Swayambhunath Stupa': '01121856758641498642233f274719d2',
  'Patan Durbar Square': '9f584e03038a499092446777c5c00e6c'
};

export const parseHeritageData = (): HeritageSite[] => {
  const lines = RAW_CSV_DATA.split('\n');

  return lines.slice(1).map((line, index) => {
    const values = line.split(',');
    const name = values[0];
    const typeStr = values[2] || '';

    const categories: SiteCategory[] = [];
    const normalizedType = typeStr.toLowerCase();

    if (normalizedType.includes('unesco')) categories.push(SiteCategory.UNESCO);
    if (normalizedType.includes('hindu')) categories.push(SiteCategory.HINDU);
    if (normalizedType.includes('buddhist') || normalizedType.includes('stupa') || normalizedType.includes('monastery')) categories.push(SiteCategory.BUDDHIST);
    if (normalizedType.includes('palace') || normalizedType.includes('fort') || normalizedType.includes('museum')) categories.push(SiteCategory.PALACE);
    if (normalizedType.includes('religious') || normalizedType.includes('cave') || normalizedType.includes('hill')) categories.push(SiteCategory.RELIGIOUS);
    if (normalizedType.includes('natural')) categories.push(SiteCategory.NATURAL);
    if (normalizedType.includes('archaeological')) categories.push(SiteCategory.ARCHAEOLOGICAL);

    if (categories.length === 0) categories.push(SiteCategory.RELIGIOUS);

    return {
      id: `site-${index}`,
      name,
      location: `${values[1]}, Nepal`,
      type: typeStr,
      latitude: parseFloat(values[3]),
      longitude: parseFloat(values[4]),
      significance: values[5],
      imageUrl: `https://picsum.photos/seed/${encodeURIComponent(name)}-1/600/400`,
      images: [
        `https://picsum.photos/seed/${encodeURIComponent(name)}-1/600/400`,
        `https://picsum.photos/seed/${encodeURIComponent(name)}-2/600/400`,
        `https://picsum.photos/seed/${encodeURIComponent(name)}-3/600/400`
      ],
      historicalBackground: `The ${name} dates back several centuries, representing a pivotal era in Nepalese history. It was developed during the ${index % 2 === 0 ? 'Malla' : 'Lichhavi'} period by visionary architects and artisans.`,
      culturalImportance: `As a primary ${typeStr}, this site serves as a spiritual beacon for thousands. It is the center of local festivals like ${index % 3 === 0 ? 'Indra Jatra' : 'Dashain'} and holds immense sacred value in the Nepalese consciousness.`,
      architecture: index % 2 === 0 ? 'Multi-tiered Pagoda style with intricate wood carvings and stone masonry' : 'Hemispherical Dome (Stupa) with gilded spires and watchful eyes of Buddha',
      era: index % 2 === 0 ? '17th Century (Medieval)' : 'Ancient (Pre-Lichhavi Era)',
      unescoStatus: normalizedType.includes('unesco'),
      bestTime: 'October to March (Ideal for clear skies and festivals)',
      legend: index % 4 === 0 ? 'Ancient texts suggest that divine intervention guided the selection of this sacred geography, making it a powerful portal for spiritual seekers.' : undefined,
      sketchfabId: SKETCHFAB_MAP[name] || undefined,
      categories
    };
  });
};

