        disableClusteringAtZoom: 17,
        iconCreateFunction: (cluster: any) => {
          const count = cluster.getChildCount();
          return L.divIcon({
            html: `
              <div class="flex items-center justify-center">
                <div class="relative w-12 h-12 flex items-center justify-center bg-[#2d9a91] text-white font-black border-4 border-white shadow-2xl">
                  ${count}
                </div>
              </div>
            `,
            className: 'custom-cluster-icon',
            iconSize: L.point(48, 48)
          });
        }
      });
      map.addLayer(clusterGroupRef.current!);
    }

    const clusterGroup = clusterGroupRef.current!;
    clusterGroup.clearLayers();
    markerMapRef.current.clear();

    sites.forEach((site) => {
      const marker = L.marker([site.latitude, site.longitude], {
        icon: createCustomIcon(site)
      });

      marker.on('click', () => {
        onSiteSelect(site);
      });

      // We bind the popup only once to avoid root-creation defects
      const container = document.createElement('div');
      const root = createRoot(container);
      root.render(<SiteDetailsPopup site={site} />);

      marker.bindPopup(container, { 
        minWidth: 420,
        maxWidth: 420,
        closeButton: true,
        offset: [0, -10],
        className: 'custom-rich-popup'
      });

      markerMapRef.current.set(site.id, marker);
      clusterGroup.addLayer(marker);
    });

    return () => {
      if (clusterGroup && map.hasLayer(clusterGroup)) {
        map.removeLayer(clusterGroup);
      }
      clusterGroupRef.current = null;
    };
  }, [sites, map, onSiteSelect]);

  useEffect(() => {
    if (activeSite && markerMapRef.current.has(activeSite.id)) {
      const marker = markerMapRef.current.get(activeSite.id)!;
      map.flyTo([activeSite.latitude, activeSite.longitude], 16, { duration: 1.2 });
      setTimeout(() => marker.openPopup(), 1300);
    }
  }, [activeSite, map]);

  return null;
};

const AdminBoundaries: React.FC = () => {
  const [zoom, setZoom] = useState(DEFAULT_ZOOM);
  const [provinceData, setProvinceData] = useState<any>(null);

  useMapEvents({
    zoomend: (e) => { setZoom(e.target.getZoom()); }
  });

  useEffect(() => {
    fetch('https://raw.githubusercontent.com/nepal-maps/nepal-maps.github.io/master/geojson/province.json')
      .then(res => res.json())
      .then(data => setProvinceData(data))
      .catch(err => console.error("Admin boundary fetch failed", err));
  }, []);

  const provinceStyle = { color: '#000000', weight: 2, opacity: 0.5, fillOpacity: 0.01, dashArray: '5, 5' };

  return provinceData && zoom < 10 ? <GeoJSON data={provinceData} style={provinceStyle} interactive={false} /> : null;
};

const LegendIcon = ({ category }: { category: SiteCategory }) => {
  let path = "";
  switch (category) {
    case SiteCategory.UNESCO: path = '<path d="M4 22h16v-2H4v2zM2 6v2h20V6H2zm2 12h2v-8H4v8zm5 0h2v-8H9v8zm5 0h2v-8h-2v8zm5 0h2v-8h-2v8zM2 2v2h20V2H2z"/>'; break;
    case SiteCategory.HINDU: path = '<path d="M12 2L4 7h16L12 2zM12 7l-7 5h14l-7-5zM12 12l-8 5h16l-8-5zM5 17v3h14v-3H5z"/>'; break;
    case SiteCategory.BUDDHIST: path = '<path d="M12 2c-1 0-2 1-2 2h4c0-1-1-2-2-2zM7 12c0-3 2-5 5-5s5 2 5 5v2H7v-2zM5 16h14v2H5v-2zM4 20h16v2H4v-2z"/>'; break;
    case SiteCategory.PALACE: path = '<path d="M3 21h18v-2h-1V9l-4-4-4 4v10H10V9L6 5 2 9v10H1V21z"/>'; break;
    case SiteCategory.RELIGIOUS: path = '<path d="M12 2C12 2 7 7 7 12s5 10 5 10s5-5 5-10s-5-10-5-10zm0 16c-3.3 0-6-2.7-6-6s6-10 6-10s6 6.7 6 10s-2.7 6-6 6z"/>'; break;
    case SiteCategory.NATURAL: path = '<path d="M14 10l-4 6l-3-2l-5 7h20zM22 21h-20v-2l5-7l3 2l4-6l5 6v7z"/>'; break;
    case SiteCategory.ARCHAEOLOGICAL: path = '<path d="M6 5h12v2H6V5zm3 14h6v-10H9v10zm-5 2h16v-2H4v2z"/>'; break;
  }
  return <svg viewBox="0 0 24 24" className="w-3 h-3 text-white" fill="currentColor" dangerouslySetInnerHTML={{ __html: path }} />;
};

