import { createCustomIcon } from './CustomMarker';
import SiteDetailsPopup from './SiteDetailsPopup';

// LEAFLET ICON FIX: Force icons to load from CDN to avoid 404s in local dev
delete (L.Icon.Default.prototype as any)._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
  iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
});

const LocationHandler: React.FC<{ trigger: number }> = ({ trigger }) => {
  const map = useMap();
  const layerRef = useRef<L.LayerGroup | null>(null);

  useEffect(() => {
    if (trigger > 0) {
      if (layerRef.current) layerRef.current.clearLayers();
      else layerRef.current = L.layerGroup().addTo(map);

      map.locate({ setView: true, maxZoom: 16 });

      const onLocationFound = (e: L.LocationEvent) => {
        L.circle(e.latlng, { radius: e.accuracy, color: '#2d9a91', weight: 1, fillOpacity: 0.1 }).addTo(layerRef.current!);
        L.marker(e.latlng, {
          icon: L.divIcon({
            html: '<div class="w-4 h-4 bg-blue-500 border-2 border-white pulse"></div>',
            className: 'gps-marker',
            iconSize: [16, 16]
          })
        }).addTo(layerRef.current!);
      };

      map.on('locationfound', onLocationFound);
      return () => { map.off('locationfound', onLocationFound); };
    }
  }, [trigger, map]);

  return null;
};

const MarkerClusterGroup: React.FC<{ 
  sites: HeritageSite[]; 
  activeSite: HeritageSite | null;
  onSiteSelect: (site: HeritageSite) => void 
}> = ({ sites, activeSite, onSiteSelect }) => {
  const map = useMap();
  const clusterGroupRef = useRef<any>(null);
  const markerMapRef = useRef<Map<string, L.Marker>>(new Map());

  useEffect(() => {
    if (!clusterGroupRef.current) {
      clusterGroupRef.current = (L as any).markerClusterGroup({
        chunkedLoading: true,
        maxClusterRadius: 45,
        showCoverageOnHover: false,
        spiderfyOnMaxZoom: true,
        disableClusteringAtZoom: 16,
        iconCreateFunction: (cluster: any) => {
          const count = cluster.getChildCount();
          return L.divIcon({
            html: `
              <div class="flex items-center justify-center">
                <div class="relative w-12 h-12 flex items-center justify-center bg-[#2d9a91] text-white font-black border-4 border-white shadow-2xl">
                  ${count}
                </div>
              </div>
            `,
            className: 'custom-cluster-icon',
            iconSize: L.point(48, 48)
          });
        }
      });
      map.addLayer(clusterGroupRef.current!);
    }

    const clusterGroup = clusterGroupRef.current!;
    clusterGroup.clearLayers();
    markerMapRef.current.clear();

    sites.forEach((site) => {
      const marker = L.marker([site.latitude, site.longitude], {
        icon: createCustomIcon(site)
      });

      marker.on('click', () => {
        onSiteSelect(site);
      });

      const container = document.createElement('div');
      const root = createRoot(container);
      root.render(<SiteDetailsPopup site={site} />);

      marker.bindPopup(container, { 
        minWidth: 420,
        maxWidth: 420,
        closeButton: true,
        offset: [0, -10],
        className: 'custom-rich-popup'
      });

      markerMapRef.current.set(site.id, marker);
      clusterGroup.addLayer(marker);
    });

    return () => {
      // We don't remove the whole layer on every sites change to avoid flickering
    };
  }, [sites, map, onSiteSelect]);

  useEffect(() => {
    if (activeSite && markerMapRef.current.has(activeSite.id)) {
      const marker = markerMapRef.current.get(activeSite.id)!;
      map.flyTo([activeSite.latitude, activeSite.longitude], 16, { duration: 1.2 });
      setTimeout(() => marker.openPopup(), 1300);
    }
  }, [activeSite, map]);

  return null;
};

const AdminBoundaries: React.FC = () => {
  const [zoom, setZoom] = useState(DEFAULT_ZOOM);
  const [provinceData, setProvinceData] = useState<any>(null);

  useMapEvents({
    zoomend: (e) => { setZoom(e.target.getZoom()); }
  });

  useEffect(() => {
    const fetchBoundaries = async () => {
      try {
        const res = await fetch('https://raw.githubusercontent.com/nepal-maps/nepal-maps.github.io/master/geojson/province.json');
        if (!res.ok) throw new Error('Boundary fetch failed');
        const rawText = await res.text();

        // AGGRESSIVE JSON CLEANING: Find the first '{' and last '}' to skip BOM or junk
        const start = rawText.indexOf('{');
        const end = rawText.lastIndexOf('}');
        if (start === -1 || end === -1) throw new Error("Invalid JSON structure");

        const cleanJson = rawText.substring(start, end + 1);
        const data = JSON.parse(cleanJson);
        setProvinceData(data);
      } catch (err) {
        console.warn("Boundary error (expected for some cross-origin files):", err);
      }
    };

    fetchBoundaries();
  }, []);

  const provinceStyle = { color: '#000000', weight: 1.5, opacity: 0.15, fillOpacity: 0.01, dashArray: '4, 4' };

  return provinceData && zoom < 10 ? <GeoJSON data={provinceData} style={provinceStyle} interactive={false} /> : null;
};

const LegendIcon = ({ category }: { category: SiteCategory }) => {
  let path = "";
  switch (category) {
    case SiteCategory.UNESCO: path = '<path d="M4 22h16v-2H4v2zM2 6v2h20V6H2zm2 12h2v-8H4v8zm5 0h2v-8H9v8zm5 0h2v-8h-2v8zm5 0h2v-8h-2v8zM2 2v2h20V2H2z"/>'; break;
    case SiteCategory.HINDU: path = '<path d="M12 2L4 7h16L12 2zM12 7l-7 5h14l-7-5zM12 12l-8 5h16l-8-5zM5 17v3h14v-3H5z"/>'; break;
    case SiteCategory.BUDDHIST: path = '<path d="M12 2c-1 0-2 1-2 2h4c0-1-1-2-2-2zM7 12c0-3 2-5 5-5s5 2 5 5v2H7v-2zM5 16h14v2H5v-2z" /> <path d="M4 20h16v2H4v-2z" />'; break;
    case SiteCategory.PALACE: path = '<path d="M3 21h18v-2h-1V9l-4-4-4 4v10H10V9L6 5 2 9v10H1V21z"/>'; break;
    case SiteCategory.RELIGIOUS: path = '<path d="M12 2C12 2 7 7 7 12s5 10 5 10s5-5 5-10s-5-10-5-10zm0 16c-3.3 0-6-2.7-6-6s6-10 6-10s6 6.7 6 10s-2.7 6-6 6z"/>'; break;
    case SiteCategory.NATURAL: path = '<path d="M14 10l-4 6l-3-2l-5 7h20zM22 21h-20v-2l5-7l3 2l4-6l5 6v7z"/>'; break;
    case SiteCategory.ARCHAEOLOGICAL: path = '<path d="M6 5h12v2H6V5zm3 14h6v-10H9v10zm-5 2h16v-2H4v2z"/>'; break;
  }
  return <svg viewBox="0 0 24 24" className="w-3 h-3 text-white" fill="currentColor" dangerouslySetInnerHTML={{ __html: path }} />;
};

interface MapViewProps {
  sites: HeritageSite[];
  activeSite: HeritageSite | null;
  onSiteSelect: (site: HeritageSite) => void;
  mapType: 'osm' | 'light' | 'satellite';
  locateMe: number;
}

const MapView: React.FC<MapViewProps> = ({ sites, activeSite, onSiteSelect, mapType, locateMe }) => {
  const getTileLayer = () => {
    switch(mapType) {
      case 'light': return 'https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png';
      case 'satellite': return 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}';
      default: return 'https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png';
    }
  };

  return (
    <div className="w-full h-full relative z-[1]">
      <MapContainer 
        center={DEFAULT_NEPAL_CENTER} 
        zoom={DEFAULT_ZOOM} 
        className="w-full h-full"
        zoomControl={false}
        preferCanvas={true}
      >
        <TileLayer attribution='&copy; OpenStreetMap' url={getTileLayer()} />
        <ZoomControl position="bottomright" />
        <LocationHandler trigger={locateMe} />
        <AdminBoundaries />
        <MarkerClusterGroup sites={sites} activeSite={activeSite} onSiteSelect={onSiteSelect} />
      </MapContainer>

      {/* Legend */}
      <div className="absolute bottom-10 left-6 z-[1000] bg-white p-5 shadow-2xl border border-gray-200 hidden md:block w-[240px]">
        <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 border-b border-gray-100 pb-2">Heritage Categories</h4>
        <div className="space-y-3">
          {Object.entries(CATEGORY_COLORS).map(([cat, color]) => (
            <div key={cat} className="flex items-center gap-3">
              <div className="w-7 h-7 flex items-center justify-center" style={{ backgroundColor: color }}>
                <LegendIcon category={cat as SiteCategory} />
              </div>
              <span className="text-[10px] font-black text-gray-700 uppercase tracking-tight">{cat}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default MapView;

import React, { useState, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import MapView from './components/MapView';
import { HeritageSite, SiteCategory } from './types';
import { parseHeritageData } from './utils/dataParser';
import { Layers, Home, Map as MapIcon, ChevronDown, Navigation, ArrowRight } from 'lucide-react';

const App: React.FC = () => {
  const allSites = useMemo(() => parseHeritageData(), []);

  const [showMap, setShowMap] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategories, setSelectedCategories] = useState<SiteCategory[]>(Object.values(SiteCategory));
  const [activeSite, setActiveSite] = useState<HeritageSite | null>(null);
  const [mapType, setMapType] = useState<'osm' | 'light' | 'satellite'>('light');
  const [showLayerSelect, setShowLayerSelect] = useState(false);
  const [locateMe, setLocateMe] = useState(0);

  const filteredSites = useMemo(() => {
    return allSites.filter(site => {
      const matchesSearch = site.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           site.location.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = site.categories.some(cat => selectedCategories.includes(cat));
      return matchesSearch && matchesCategory;
    });
  }, [allSites, searchTerm, selectedCategories]);

  const handleFilterToggle = (category: SiteCategory) => {
    setSelectedCategories(prev => 
      prev.includes(category) 
        ? prev.filter(c => c !== category) 
        : [...prev, category]
    );
  };

  const handleSiteSelect = (site: HeritageSite) => {
    setActiveSite(site);
  };

  const layers = [
    { id: 'light', label: 'Light Canvas', desc: 'CartoDB Positron' },
    { id: 'osm', label: 'Street Map', desc: 'OpenStreetMap Standard' },
    { id: 'satellite', label: 'Satellite View', desc: 'ArcGIS World Imagery' }
  ];

  if (!showMap) {
    return (
      <div className="h-screen w-screen relative overflow-hidden bg-gray-900 flex flex-col items-center justify-center">
        {/* Background Image with Overlay */}
        <div className="absolute inset-0 z-0">
          <img 
            src="https://images.unsplash.com/photo-1544735716-392fe2489ffa?q=80&w=2071&auto=format&fit=crop" 
            className="w-full h-full object-cover opacity-40"
            alt="Heritage Background"
          />
          <div className="absolute inset-0 bg-gradient-to-b from-gray-900/40 via-gray-900/80 to-gray-900"></div>
        </div>

        {/* Content */}
        <div className="relative z-10 flex flex-col items-center text-center px-6 max-w-4xl fade-in-up">
           <div className="w-24 h-24 bg-white p-3 mb-10 shadow-2xl">
              <div className="w-full h-full border-4 border-red-600 flex items-center justify-center">
                 <span className="text-[12px] font-black text-red-600 leading-none">MAPPERS<br/>NEPAL</span>
              </div>
           </div>

           <h1 className="text-6xl md:text-8xl font-black text-white uppercase tracking-tighter mb-4">
             Heritage Mapping <br/> <span className="text-red-600">in Nepal</span>
           </h1>

           <p className="text-gray-400 text-lg md:text-xl font-medium tracking-widest uppercase mb-12 max-w-2xl leading-relaxed">
             An Interactive WebGIS Journey Through Ancient Civilizations, Cultural Landscapes, and Sacred Landmarks.
           </p>

           <div className="flex flex-col md:flex-row gap-6">
              <button 
                onClick={() => setShowMap(true)}
                className="group relative flex items-center gap-4 bg-red-600 text-white px-10 py-6 text-sm font-black uppercase tracking-[0.3em] transition-all hover:bg-white hover:text-gray-900"
              >
                Go to Map
                <ArrowRight size={20} className="group-hover:translate-x-2 transition-transform" />
              </button>
           </div>

           <div className="mt-20 border-t border-white/10 pt-8 w-full">
              <p className="text-[10px] font-black text-white/40 uppercase tracking-[0.5em]">Digital Heritage Project by Mappers Nepal &copy; 2024</p>
           </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen w-screen bg-white overflow-hidden">
      {/* Centered Header with Logo and Branding */}
      <header className="h-24 bg-white border-b border-gray-200 flex items-center justify-center px-8 shrink-0 z-[1001]">
        <div className="flex items-center gap-6">
          <button onClick={() => setShowMap(false)} className="w-16 h-16 bg-gray-100 border border-gray-200 flex items-center justify-center p-2 hover:border-red-600 transition-colors">
            <div className="w-full h-full border-2 border-red-600 flex items-center justify-center">
               <span className="text-[8px] font-black text-red-600 text-center leading-none">MAPPERS<br/>NEPAL</span>
            </div>
          </button>

          <div className="flex flex-col items-center">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-gray-900 text-white flex items-center justify-center">
                <MapIcon size={20} />
              </div>
              <h1 className="text-2xl font-black text-gray-900 tracking-tighter uppercase">Heritage Mapping in Nepal</h1>
            </div>
            <p className="text-[10px] font-bold text-red-600 uppercase tracking-[0.5em] mt-1">Prepared by Mappers Nepal</p>
          </div>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden relative">
        <Sidebar 
          sites={filteredSites}
          onSearch={setSearchTerm}
          onFilterToggle={handleFilterToggle}
          selectedCategories={selectedCategories}
          activeSiteId={activeSite?.id || null}
          onSiteClick={handleSiteSelect}
        />

        <main className="flex-1 relative bg-gray-50 overflow-hidden">
          {/* Unified Map Controls */}
          <div className="absolute top-6 right-6 z-[1000] flex flex-col gap-2">
            <div className="relative">
              <button 
                onClick={() => setShowLayerSelect(!showLayerSelect)}
                className={`flex items-center justify-between gap-4 h-14 min-w-[220px] px-6 bg-white shadow-2xl border border-gray-200 transition-all ${
                  showLayerSelect ? 'border-red-600' : ''
                }`}
              >
                <div className="flex items-center gap-3">
                   <Layers size={18} className="text-gray-500" />
                   <span className="text-[10px] font-black text-gray-800 uppercase tracking-widest">
                     {layers.find(l => l.id === mapType)?.label}
                   </span>
                </div>
                <ChevronDown size={14} className={`text-gray-400 transition-transform ${showLayerSelect ? 'rotate-180' : ''}`} />
              </button>

              {showLayerSelect && (
                <div className="absolute right-0 mt-1 w-full bg-white shadow-2xl border border-gray-100 py-1">
                  {layers.map(layer => (
                    <button
                      key={layer.id}
                      onClick={() => { setMapType(layer.id as any); setShowLayerSelect(false); }}
                      className={`w-full text-left px-5 py-3 hover:bg-gray-50 flex flex-col border-l-4 transition-colors ${
                        mapType === layer.id ? 'bg-red-50 border-red-600' : 'border-transparent'
                      }`}
                    >
                      <span className={`text-[10px] font-black uppercase tracking-wider ${mapType === layer.id ? 'text-red-600' : 'text-gray-700'}`}>
                        {layer.label}
                      </span>
                    </button>
                  ))}
                </div>
              )}
            </div>

            <button 
              onClick={() => setLocateMe(prev => prev + 1)}
              className="h-14 w-full bg-white shadow-2xl flex items-center justify-center text-gray-600 hover:text-red-600 transition-all border border-gray-200 group gap-3 px-6"
            >
              <Navigation size={18} />
              <span className="text-[10px] font-black uppercase tracking-widest">Find My Location</span>
            </button>

            <button 
              onClick={() => { setActiveSite(null); setSearchTerm(''); }}
              className="h-14 w-full bg-white shadow-2xl flex items-center justify-center text-gray-600 hover:text-red-600 transition-all border border-gray-200 gap-3 px-6"
            >
              <Home size={18} />
              <span className="text-[10px] font-black uppercase tracking-widest">Reset View</span>
            </button>
          </div>

          <MapView 
            sites={filteredSites} 
            activeSite={activeSite}
            onSiteSelect={handleSiteSelect}
            mapType={mapType}
            locateMe={locateMe}
          />
        </main>
      </div>
    </div>
  );
};

export default App;

