import React, { useEffect, useRef, useState } from 'react';
import 'ol/ol.css';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import VectorSource from 'ol/source/Vector';
import Cluster from 'ol/source/Cluster';
import OSM from 'ol/source/OSM';
import XYZ from 'ol/source/XYZ';
import GeoJSON from 'ol/format/GeoJSON';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import { fromLonLat } from 'ol/proj';
import { Style, Icon, Circle, Fill, Stroke, Text } from 'ol/style';
import Overlay from 'ol/Overlay';
import { createRoot } from 'react-dom/client';
import { HeritageSite, SiteCategory } from '../types';
import { DEFAULT_NEPAL_CENTER, DEFAULT_ZOOM, CATEGORY_COLORS } from '../constants';
import SiteDetailsPopup from './SiteDetailsPopup';

interface MapViewProps {
  sites: HeritageSite[];
  activeSite: HeritageSite | null;
  onSiteSelect: (site: HeritageSite) => void;
  mapType: 'osm' | 'light' | 'satellite';
  locateMe: number;
}

const MapView: React.FC<MapViewProps> = ({ sites, activeSite, onSiteSelect, mapType, locateMe }) => {
  const mapElement = useRef<HTMLDivElement>(null);
  const popupElement = useRef<HTMLDivElement>(null);
  const mapRef = useRef<Map | null>(null);
  const popupOverlayRef = useRef<Overlay | null>(null);
  const popupRootRef = useRef<any>(null);
  const vectorSourceRef = useRef<VectorSource | null>(null);

  // Initialize Map
  useEffect(() => {
    if (!mapElement.current) return;

    const vectorSource = new VectorSource();
    vectorSourceRef.current = vectorSource;

    const clusterSource = new Cluster({
      distance: 40,
      minDistance: 20,
      source: vectorSource,
    });

    const styleCache: any = {};
    const clusterLayer = new VectorLayer({
      source: clusterSource,
      style: (feature) => {
        const size = feature.get('features').length;
        let style = styleCache[size];

        if (size > 1) {
          if (!style) {
            style = new Style({
              image: new Circle({
                radius: 20,
                stroke: new Stroke({ color: '#fff', width: 4 }),
                fill: new Fill({ color: '#2d9a91' }),
              }),
              text: new Text({
                text: size.toString(),
                fill: new Fill({ color: '#fff' }),
                font: 'bold 12px Inter, sans-serif',
              }),
            });
            styleCache[size] = style;
          }
          return style;
        }

        // Single marker style
        const site: HeritageSite = feature.get('features')[0].get('site');
        const color = CATEGORY_COLORS[site.categories[0]] || '#333';

        return new Style({
          image: new Circle({
            radius: 12,
            fill: new Fill({ color: color }),
            stroke: new Stroke({ color: '#fff', width: 3 }),
          }),
        });
      },
    });

    const tileLayer = new TileLayer({
      source: new OSM(),
    });

    const boundaryLayer = new VectorLayer({
      source: new VectorSource({
        url: 'https://raw.githubusercontent.com/nepal-maps/nepal-maps.github.io/master/geojson/province.json',
        format: new GeoJSON(),
      }),
      style: new Style({
        stroke: new Stroke({
          color: 'rgba(0, 0, 0, 0.1)',
          width: 1,
          lineDash: [4, 4],
        }),
        fill: new Fill({ color: 'rgba(0,0,0,0)' }),
      }),
    });

    const popupOverlay = new Overlay({
      element: popupElement.current!,
      autoPan: {
        animation: { duration: 250 },
      },
    });
    popupOverlayRef.current = popupOverlay;

    const map = new Map({
      target: mapElement.current,
      layers: [tileLayer, boundaryLayer, clusterLayer],
      view: new View({
        center: fromLonLat([DEFAULT_NEPAL_CENTER[1], DEFAULT_NEPAL_CENTER[0]]),
        zoom: DEFAULT_ZOOM,
      }),
      overlays: [popupOverlay],
    });

    mapRef.current = map;

    // Handle Clicks
    map.on('click', (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (feat) => feat);
      if (feature) {
        const features = feature.get('features');
        if (features && features.length === 1) {
          const site = features[0].get('site');
          onSiteSelect(site);
        } else if (features && features.length > 1) {
          // Zoom into cluster
          const extent = feature.getGeometry().getExtent();
          map.getView().fit(extent, { duration: 500, maxZoom: 12 });
        }
      } else {
        popupOverlay.setPosition(undefined);
      }
    });

    return () => map.setTarget(undefined);
  }, []);

  // Update Sites
  useEffect(() => {
    if (!vectorSourceRef.current) return;
    vectorSourceRef.current.clear();

    const features = sites.map((site) => {
      const feature = new Feature({
        geometry: new Point(fromLonLat([site.longitude, site.latitude])),
      });
      feature.set('site', site);
      return feature;
    });

    vectorSourceRef.current.addFeatures(features);
  }, [sites]);

  // Update Map Type
  useEffect(() => {
    if (!mapRef.current) return;
    const layers = mapRef.current.getLayers();
    const baseLayer = layers.item(0) as TileLayer<any>;

    let newSource;
    switch (mapType) {
      case 'light':
        newSource = new XYZ({ url: 'https://{a-c}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png' });
        break;
      case 'satellite':
        newSource = new XYZ({ url: 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}' });
        break;
      default:
        newSource = new OSM();
    }
    baseLayer.setSource(newSource);
  }, [mapType]);

  // Handle Active Site Selection
  useEffect(() => {
    if (!activeSite || !mapRef.current || !popupOverlayRef.current) return;

    const coordinate = fromLonLat([activeSite.longitude, activeSite.latitude]);
    mapRef.current.getView().animate({
      center: coordinate,
      zoom: 15,
      duration: 1000,
    });

    // Render Popup
    if (!popupRootRef.current) {
      popupRootRef.current = createRoot(popupElement.current!);
    }
    popupRootRef.current.render(<SiteDetailsPopup site={activeSite} />);
    popupOverlayRef.current.setPosition(coordinate);
  }, [activeSite]);

  // Handle Geolocation
  useEffect(() => {
    if (locateMe === 0 || !mapRef.current) return;

    navigator.geolocation.getCurrentPosition((pos) => {
      const coords = fromLonLat([pos.coords.longitude, pos.coords.latitude]);
      mapRef.current?.getView().animate({
        center: coords,
        zoom: 16,
        duration: 1000,
      });
    });
  }, [locateMe]);

  return (
    <div className="w-full h-full relative">
      <div ref={mapElement} className="w-full h-full" />
      <div ref={popupElement} className="ol-popup" />

      {/* Legend */}
      <div className="absolute bottom-10 left-6 z-[10] bg-white p-5 shadow-2xl border border-gray-200 hidden md:block w-[240px]">
        <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 border-b border-gray-100 pb-2">Heritage Categories</h4>
        <div className="space-y-3">
          {Object.entries(CATEGORY_COLORS).map(([cat, color]) => (
            <div key={cat} className="flex items-center gap-3">
              <div className="w-6 h-6 border-2 border-white shadow-sm" style={{ backgroundColor: color }} />
              <span className="text-[10px] font-black text-gray-700 uppercase tracking-tight">{cat}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default MapView;

