            <div className="relative group max-w-full max-h-full">
               <img 
                 src={site.images[activeImageIndex]} 
                 className="max-w-full max-h-full object-contain shadow-[0_0_100px_rgba(0,0,0,0.5)] transition-transform duration-500" 
                 alt={site.name}
               />
               <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-black/80 to-transparent translate-y-2 opacity-0 group-hover:translate-y-0 group-hover:opacity-100 transition-all">
                  <h3 className="text-white text-lg font-black uppercase tracking-widest">{site.name}</h3>
                  <p className="text-red-500 text-[10px] font-black uppercase tracking-[0.3em] mt-1">{site.location}</p>
               </div>
            </div>

            <button 
              onClick={nextImage} 
              className="absolute right-4 md:right-10 w-12 h-12 md:w-16 md:h-16 flex items-center justify-center text-white/30 hover:text-white hover:bg-white/10 transition-all"
            >
              <ChevronRight size={48} />
            </button>
          </div>

          {/* Footer Navigation */}
          <div className="absolute bottom-8 flex gap-3">
             {site.images.map((_, idx) => (
               <button 
                 key={idx}
                 onClick={(e) => { e.stopPropagation(); setActiveImageIndex(idx); }}
                 className={`w-3 h-3 transition-all ${idx === activeImageIndex ? 'bg-red-600 scale-125' : 'bg-white/20 hover:bg-white/50'}`}
               />
             ))}
          </div>
        </div>,
        document.body
      )}
    </div>
