import React, { useEffect, useRef } from 'react';
import Map from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import VectorLayer from 'ol/layer/Vector';
import VectorSource from 'ol/source/Vector';
import Cluster from 'ol/source/Cluster';
import OSM from 'ol/source/OSM';
import XYZ from 'ol/source/XYZ';
import GeoJSON from 'ol/format/GeoJSON';
import Feature from 'ol/Feature';
import Point from 'ol/geom/Point';
import { fromLonLat } from 'ol/proj';
import { Style, Circle, Fill, Stroke } from 'ol/style';
import Overlay from 'ol/Overlay';
import { createRoot } from 'react-dom/client';
import { HeritageSite } from '../types';
import { DEFAULT_NEPAL_CENTER, DEFAULT_ZOOM, CATEGORY_COLORS } from '../constants';
import SiteDetailsPopup from './SiteDetailsPopup';

interface MapViewProps {
  sites: HeritageSite[];
  activeSite: HeritageSite | null;
  onSiteSelect: (site: HeritageSite) => void;
  mapType: 'osm' | 'light' | 'satellite';
  locateMe: number;
}

const MapView: React.FC<MapViewProps> = ({ sites, activeSite, onSiteSelect, mapType, locateMe }) => {
  const mapElement = useRef<HTMLDivElement>(null);
  const popupElement = useRef<HTMLDivElement>(null);
  const mapRef = useRef<Map | null>(null);
  const popupOverlayRef = useRef<Overlay | null>(null);
  const popupRootRef = useRef<any>(null);
  const vectorSourceRef = useRef<VectorSource | null>(null);
  const locationSourceRef = useRef<VectorSource | null>(null);

  const onSiteSelectRef = useRef(onSiteSelect);
  useEffect(() => {
    onSiteSelectRef.current = onSiteSelect;
  }, [onSiteSelect]);

  // Initialize Map
  useEffect(() => {
    if (!mapElement.current) return;

    // Heritage Sites Source
    const vectorSource = new VectorSource();
    vectorSourceRef.current = vectorSource;

    // User Location Source
    const locationSource = new VectorSource();
    locationSourceRef.current = locationSource;

    const clusterSource = new Cluster({
      distance: 35,
      minDistance: 15,
      source: vectorSource,
    });

    const styleCache: any = {};
    const clusterLayer = new VectorLayer({
      source: clusterSource,
      style: (feature) => {
        const features = feature.get('features');
        const size = features ? features.length : 0;

        if (size > 1) {
          let style = styleCache[size];
          if (!style) {
            style = new Style({
              image: new Circle({
                radius: 18,
                stroke: new Stroke({ color: '#fff', width: 2 }),
                fill: new Fill({ color: '#dc2626' }),
              }),
              text: new Text({
                text: size.toString(),
                fill: new Fill({ color: '#fff' }),
                font: 'bold 11px Inter, sans-serif',
              }) as any,
            });
            styleCache[size] = style;
          }
          return style;
        }

        if (size === 1) {
            const site: HeritageSite = features[0].get('site');
            const color = CATEGORY_COLORS[site.categories[0]] || '#333';

            return new Style({
              image: new Circle({
                radius: 9,
                fill: new Fill({ color: color }),
                stroke: new Stroke({ color: '#fff', width: 2 }),
              }),
            });
        }
        return null;
      },
    });

    // Location Marker Style (Blue Dot)
    const locationLayer = new VectorLayer({
      source: locationSource,
      style: new Style({
        image: new Circle({
          radius: 8,
          fill: new Fill({ color: '#3b82f6' }),
          stroke: new Stroke({ color: '#fff', width: 3 }),
        }),
      }),
      zIndex: 100,
    });

    const baseLayer = new TileLayer({
      source: new XYZ({ url: 'https://{a-c}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png' }),
    });

    const boundaryLayer = new VectorLayer({
      source: new VectorSource({
        url: 'https://raw.githubusercontent.com/nepal-maps/nepal-maps.github.io/master/geojson/province.json',
        format: new GeoJSON(),
      }),
      style: new Style({
        stroke: new Stroke({ color: 'rgba(0, 0, 0, 0.1)', width: 1, lineDash: [4, 4] }),
        fill: new Fill({ color: 'rgba(0,0,0,0)' }),
      }),
    });

    const popupOverlay = new Overlay({
      element: popupElement.current!,
      autoPan: { animation: { duration: 300 }, margin: 100 },
      positioning: 'bottom-center'
    });
    popupOverlayRef.current = popupOverlay;

    const map = new Map({
      target: mapElement.current,
      layers: [baseLayer, boundaryLayer, clusterLayer, locationLayer],
      view: new View({
        center: fromLonLat([DEFAULT_NEPAL_CENTER[1], DEFAULT_NEPAL_CENTER[0]]),
        zoom: DEFAULT_ZOOM,
        minZoom: 5,
        maxZoom: 19
      }),
      overlays: [popupOverlay],
    });

    mapRef.current = map;

    map.on('click', (evt) => {
      const feature = map.forEachFeatureAtPixel(evt.pixel, (feat) => feat);
      if (feature) {
        const features = feature.get('features');
        if (features && features.length === 1) {
          const site = features[0].get('site');
          onSiteSelectRef.current(site);
        } else if (features && features.length > 1) {
          const extent = feature.getGeometry()!.getExtent();
          map.getView().fit(extent, { duration: 600, padding: [80, 80, 80, 80] });
        }
      } else {
        popupOverlay.setPosition(undefined);
      }
    });

    return () => {
      if (mapRef.current) {
        mapRef.current.setTarget(undefined);
        mapRef.current = null;
      }
    };
  }, []);

  // Sync sites to map
  useEffect(() => {
    if (!vectorSourceRef.current) return;
    vectorSourceRef.current.clear();
    const features = sites.map((site) => {
      const f = new Feature({ geometry: new Point(fromLonLat([site.longitude, site.latitude])) });
      f.set('site', site);
      return f;
    });
    vectorSourceRef.current.addFeatures(features);
  }, [sites]);

  // Handle Base Map Type
  useEffect(() => {
    if (!mapRef.current) return;
    const baseLayer = mapRef.current.getLayers().item(0) as TileLayer<any>;
    let newSource;
    switch (mapType) {
      case 'light': newSource = new XYZ({ url: 'https://{a-c}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png' }); break;
      case 'satellite': newSource = new XYZ({ url: 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}' }); break;
      default: newSource = new OSM();
    }
    baseLayer.setSource(newSource);
  }, [mapType]);

  // Active Site & Reset View Logic
  useEffect(() => {
    if (!mapRef.current || !popupOverlayRef.current) return;

    if (activeSite) {
      const coordinate = fromLonLat([activeSite.longitude, activeSite.latitude]);
      mapRef.current.getView().animate({ center: coordinate, zoom: 15, duration: 800 });

      if (!popupRootRef.current) {
        popupRootRef.current = createRoot(popupElement.current!);
      }
      popupRootRef.current.render(<SiteDetailsPopup site={activeSite} />);

      setTimeout(() => {
        popupOverlayRef.current?.setPosition(coordinate);
      }, 100);
    } else {
      // If we cleared the active site (RESET), zoom back to Nepal exactly like initial load
      mapRef.current.getView().animate({
        center: fromLonLat([DEFAULT_NEPAL_CENTER[1], DEFAULT_NEPAL_CENTER[0]]),
        zoom: DEFAULT_ZOOM,
        duration: 800
      });
      popupOverlayRef.current.setPosition(undefined);
    }
  }, [activeSite]);

  // Find My Location
  useEffect(() => {
    if (locateMe === 0 || !mapRef.current || !locationSourceRef.current) return;

    navigator.geolocation.getCurrentPosition((pos) => {
      const lon = pos.coords.longitude;
      const lat = pos.coords.latitude;
      const coords = fromLonLat([lon, lat]);

      // Update location marker
      locationSourceRef.current!.clear();
      const locFeature = new Feature({
        geometry: new Point(coords),
      });
      locationSourceRef.current!.addFeature(locFeature);

      mapRef.current?.getView().animate({ center: coords, zoom: 16, duration: 1000 });
    }, (err) => console.warn("Location error:", err), { enableHighAccuracy: true });
  }, [locateMe]);

  return (
    <div className="w-full h-full relative">
      <div ref={mapElement} className="w-full h-full" />
      <div ref={popupElement} className="ol-popup" />

      <div className="absolute bottom-10 left-6 z-[10] bg-white p-5 shadow-2xl border border-gray-100 hidden md:block w-[200px]">
        <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 border-b border-gray-100 pb-2">Heritage Categories</h4>
        <div className="space-y-3">
          {Object.entries(CATEGORY_COLORS).map(([cat, color]) => (
            <div key={cat} className="flex items-center gap-3">
              <div className="w-4 h-4 shadow-sm" style={{ backgroundColor: color }} />
              <span className="text-[9px] font-black text-gray-700 uppercase tracking-tight">{cat}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default MapView;

