    if (normalizedType.includes('unesco')) categories.push(SiteCategory.UNESCO);
    if (normalizedType.includes('hindu')) categories.push(SiteCategory.HINDU);
    if (normalizedType.includes('buddhist') || normalizedType.includes('stupa') || normalizedType.includes('monastery')) categories.push(SiteCategory.BUDDHIST);
    if (normalizedType.includes('palace') || normalizedType.includes('fort') || normalizedType.includes('museum')) categories.push(SiteCategory.PALACE);
    if (normalizedType.includes('religious') || normalizedType.includes('cave') || normalizedType.includes('hill')) categories.push(SiteCategory.RELIGIOUS);
    if (normalizedType.includes('natural')) categories.push(SiteCategory.NATURAL);
    if (normalizedType.includes('archaeological')) categories.push(SiteCategory.ARCHAEOLOGICAL);

    if (categories.length === 0) categories.push(SiteCategory.RELIGIOUS);

    return {
      id: `site-${index}`,
      name,
      location: `${values[1]}, Nepal`,
      type: typeStr,
      latitude: parseFloat(values[3]),
      longitude: parseFloat(values[4]),
      significance: values[5],
      imageUrl: `https://picsum.photos/seed/${encodeURIComponent(name)}-1/1200/800`,
      images: [
        `https://picsum.photos/seed/${encodeURIComponent(name)}-1/1200/800`,
        `https://picsum.photos/seed/${encodeURIComponent(name)}-2/1200/800`,
        `https://picsum.photos/seed/${encodeURIComponent(name)}-3/1200/800`
      ],
      historicalBackground: `Historical records indicate that ${name} has been a site of great importance for centuries, serving as a hub for art, spirituality, and culture in its region.`,
      culturalImportance: `This site represents the deep-rooted spiritual fabric of Nepal, drawing pilgrims and students of history from across the globe.`,
      architecture: index % 2 === 0 ? 'Traditional Newari Architecture with stone and wood masonry' : 'Sacred Religious Architecture with distinct cultural influence',
      era: 'Medieval to Contemporary',
      unescoStatus: normalizedType.includes('unesco'),
      bestTime: 'Post-monsoon season (Oct-Mar)',
      legend: 'Local oral traditions tell stories of divine manifestations that blessed this sacred location.',
      sketchfabId: SKETCHFAB_MAP[name] || undefined,
      external3dUrl: EXTERNAL_3D_MAP[name] || undefined,
      categories
    };
  });
};

import React, { useState, useEffect, useCallback } from 'react';
import { HeritageSite, SiteCategory } from '../types';
import { CATEGORY_COLORS } from '../constants';
import { 
  X, 
  ChevronLeft, 
  ChevronRight, 
  Maximize2, 
  Clock, 
  History, 
  Boxes, 
  Heart, 
  Calendar, 
  BookOpen,
  Award,
  ExternalLink,
  Search
} from 'lucide-react';

interface SiteDetailsPopupProps {
  site: HeritageSite;
}

const SiteDetailsPopup: React.FC<SiteDetailsPopupProps> = ({ site }) => {
  const [activeImageIndex, setActiveImageIndex] = useState<number | null>(null);
  const [tab, setTab] = useState<'info' | '3d'>('info');

  const openLightbox = (index: number) => {
    setActiveImageIndex(index);
    document.body.style.overflow = 'hidden';
  };

  const closeLightbox = useCallback(() => {
    setActiveImageIndex(null);
    document.body.style.overflow = 'unset';
  }, []);

  const nextImage = useCallback(() => {
    setActiveImageIndex((prev) => (prev !== null ? (prev + 1) % site.images.length : null));
  }, [site.images.length]);

  const prevImage = useCallback(() => {
    setActiveImageIndex((prev) => (prev !== null ? (prev - 1 + site.images.length) % site.images.length : null));
  }, [site.images.length]);

  // Keyboard support for Lightbox
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (activeImageIndex === null) return;
      if (e.key === 'Escape') closeLightbox();
      if (e.key === 'ArrowRight') nextImage();
      if (e.key === 'ArrowLeft') prevImage();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [activeImageIndex, closeLightbox, nextImage, prevImage]);

  return (
    <div className="w-[420px] max-h-[600px] overflow-y-auto bg-white shadow-2xl flex flex-col no-scrollbar">
      {/* Visual Header / Gallery */}
      <div className="relative h-60 bg-gray-100 shrink-0 group overflow-hidden">
        <div 
          className="relative w-full h-full cursor-pointer overflow-hidden"
          onClick={() => openLightbox(0)}
        >
          <img 
              src={site.images[0]} 
              alt={site.name} 
              className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
          />
          <div className="absolute inset-0 bg-black/30 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
             <div className="bg-white/95 p-3 rounded-full shadow-2xl transform translate-y-4 group-hover:translate-y-0 transition-all duration-300">
                <Maximize2 size={24} className="text-gray-900" />
             </div>
          </div>
        </div>

        {/* Thumbnails Overlay */}
        <div className="absolute bottom-3 right-3 flex gap-2">
          {site.images.slice(1, 3).map((img, i) => (
            <button 
              key={i} 
              onClick={() => openLightbox(i + 1)}
              className="w-12 h-12 border-2 border-white shadow-lg overflow-hidden transition-all hover:scale-110 hover:border-red-600"
            >
              <img src={img} className="w-full h-full object-cover" />
            </button>
          ))}
          <button 
            onClick={() => openLightbox(0)}
            className="w-12 h-12 bg-black/60 backdrop-blur-md text-white flex items-center justify-center border-2 border-white shadow-lg hover:bg-red-600 transition-colors"
          >
            <Search size={16} />
          </button>
        </div>

        {site.unescoStatus && (
          <div className="absolute top-4 left-4 flex items-center gap-2 bg-yellow-500 text-white px-3 py-1.5 shadow-xl">
            <Award size={14} className="fill-current" />
            <span className="text-[10px] font-black uppercase tracking-widest">UNESCO World Heritage</span>
          </div>
        )}
      </div>

      {/* Navigation Tabs */}
      <div className="flex border-b border-gray-100 bg-white sticky top-0 z-20">
        <button 
          onClick={() => setTab('info')}
          className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-colors ${tab === 'info' ? 'border-b-2 border-red-600 text-gray-900' : 'text-gray-400 hover:text-gray-600'}`}
        >
          Site Profile
        </button>
        <button 
          onClick={() => setTab('3d')}
          className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-colors ${tab === '3d' ? 'border-b-2 border-red-600 text-gray-900' : 'text-gray-400 hover:text-gray-600'}`}
        >
          Interactive 3D
        </button>
      </div>

      {/* Content Section */}
      <div className="p-6 space-y-6">
        {tab === 'info' ? (
          <>
            <div>
              <h2 className="text-2xl font-black text-gray-900 leading-none mb-2 uppercase tracking-tight">{site.name}</h2>
              <div className="flex items-center gap-2 text-gray-400">
                <Boxes size={14} />
                <p className="text-[10px] font-bold uppercase tracking-widest">{site.location}</p>
              </div>
            </div>

            <div className="flex flex-wrap gap-2">
              {site.categories.map(cat => (
                <span 
                  key={cat} 
                  className="px-2 py-1 text-[9px] font-black uppercase text-white tracking-wider"
                  style={{ backgroundColor: CATEGORY_COLORS[cat] }}
                >
                  {cat}
                </span>
              ))}
            </div>

            <p className="text-sm text-gray-600 font-medium leading-relaxed border-l-4 border-red-500 pl-4 py-1">
              {site.significance}
            </p>

            <div className="grid grid-cols-1 gap-6 pt-4 border-t border-gray-50">
              <div className="space-y-3">
                <div className="flex items-center gap-3 text-red-600">
                  <History size={18} />
                  <h4 className="text-[11px] font-black uppercase tracking-widest">Historical Context</h4>
                </div>
                <p className="text-xs text-gray-500 leading-relaxed">{site.historicalBackground}</p>
              </div>

              <div className="space-y-3">
                <div className="flex items-center gap-3 text-red-600">
                  <Heart size={18} />
                  <h4 className="text-[11px] font-black uppercase tracking-widest">Cultural Significance</h4>
                </div>
                <p className="text-xs text-gray-500 leading-relaxed">{site.culturalImportance}</p>
              </div>

              <div className="grid grid-cols-2 gap-4 bg-gray-50 p-4 border border-gray-100">
                <div className="space-y-1">
                  <span className="text-[9px] font-black text-gray-400 uppercase tracking-widest flex items-center gap-1">
                    <Boxes size={10} /> Architecture
                  </span>
                  <p className="text-[11px] font-bold text-gray-700">{site.architecture}</p>
                </div>
                <div className="space-y-1">
                  <span className="text-[9px] font-black text-gray-400 uppercase tracking-widest flex items-center gap-1">
                    <Clock size={10} /> Historical Era
                  </span>
                  <p className="text-[11px] font-bold text-gray-700">{site.era}</p>
                </div>
                <div className="space-y-1 col-span-2 mt-2">
                  <span className="text-[9px] font-black text-gray-400 uppercase tracking-widest flex items-center gap-1">
                    <Calendar size={10} /> Visitor Information
                  </span>
                  <p className="text-[11px] font-bold text-gray-700">{site.bestTime}</p>
                </div>
              </div>

              {site.legend && (
                <div className="p-4 bg-blue-50/50 border border-blue-100 flex gap-4">
                  <BookOpen size={20} className="text-blue-500 shrink-0" />
                  <div className="space-y-1">
                    <h5 className="text-[10px] font-black text-blue-900 uppercase tracking-widest">Legends & Oral Traditions</h5>
                    <p className="text-xs text-blue-800 italic leading-relaxed">{site.legend}</p>
                  </div>
                </div>
              )}
            </div>
          </>
        ) : (
          <div className="w-full flex flex-col gap-4">
             {(site.external3dUrl || site.sketchfabId) ? (
                <div className="space-y-4">
                   <div className="h-96 w-full relative group bg-black overflow-hidden shadow-2xl">
                      <iframe 
                        title={`${site.name} 3D Model`} 
                        className="w-full h-full border-none"
                        allow="autoplay; fullscreen; xr-spatial-tracking" 
                        src={site.external3dUrl || `https://sketchfab.com/models/${site.sketchfabId}/embed?autostart=1&ui_theme=dark`}
                      ></iframe>
                   </div>
                   <div className="p-4 bg-gray-900 border border-gray-800 text-white">
                      <div className="flex items-center justify-between mb-3">
                         <h4 className="text-[11px] font-black uppercase tracking-[0.2em] text-red-500">Interactive Visualization</h4>
                         <a 
                           href={site.external3dUrl || `https://sketchfab.com/models/${site.sketchfabId}`} 
                           target="_blank" 
                           rel="noopener noreferrer"
                           className="text-[9px] font-black text-white/60 uppercase flex items-center gap-1 hover:text-white transition-colors"
                         >
                           Source Link <ExternalLink size={10} />
                         </a>
                      </div>
                      <p className="text-[11px] text-gray-400 font-medium leading-relaxed">
                        Explore the intricate spatial details of {site.name}. Use your mouse to rotate (Left Click), pan (Right Click), and zoom (Scroll) into the high-resolution digital twin.
                      </p>
                   </div>
                </div>
             ) : (
                <div className="h-80 w-full flex flex-col items-center justify-center bg-gray-50 border-2 border-dashed border-gray-200 p-8 text-center">
                  <div className="w-16 h-16 bg-gray-200 flex items-center justify-center mb-4 rounded-full">
                    <Boxes size={32} className="text-gray-400" />
                  </div>
                  <h4 className="text-sm font-black text-gray-700 uppercase mb-2">3D Capture in Progress</h4>
                  <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest leading-relaxed max-w-xs">
                    Mappers Nepal is processing LIDAR data for this site. Check back soon.
                  </p>
                </div>
             )}
          </div>
        )}
      </div>

      {/* FULLSCREEN LIGHTBOX (Facebook-style) */}
      {activeImageIndex !== null && (
        <div 
          className="fixed inset-0 z-[10000] bg-black/98 flex flex-col items-center justify-center animate-in fade-in duration-300"
          onClick={closeLightbox}
        >
          {/* Close Button Top-Right */}
          <button 
            className="absolute top-6 right-6 text-white/50 hover:text-white hover:bg-white/10 transition-all p-3 rounded-full z-[10002]"
            onClick={(e) => { e.stopPropagation(); closeLightbox(); }}
          >
            <X size={32} strokeWidth={2} />
          </button>

          {/* Image Container */}
          <div 
            className="relative w-full h-full flex items-center justify-center select-none"
            onClick={(e) => e.stopPropagation()}
          >
            {/* Prev Button */}
            <button 
              onClick={prevImage}
              className="absolute left-6 w-16 h-16 bg-black/20 hover:bg-white/10 text-white rounded-full flex items-center justify-center transition-all group z-10"
            >
              <ChevronLeft size={48} strokeWidth={1} />
            </button>

            <div className="w-full h-full flex items-center justify-center p-4 md:p-12 overflow-hidden">
               <img 
                 src={site.images[activeImageIndex]} 
                 alt={`${site.name} view`}
                 className="max-w-full max-h-full object-contain shadow-2xl transition-transform duration-300 transform scale-100"
               />
            </div>

            {/* Next Button */}
            <button 
              onClick={nextImage}
              className="absolute right-6 w-16 h-16 bg-black/20 hover:bg-white/10 text-white rounded-full flex items-center justify-center transition-all group z-10"
            >
              <ChevronRight size={48} strokeWidth={1} />
            </button>
          </div>

          {/* Footer Metadata Overlay */}
          <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-black/80 to-transparent p-12 flex flex-col items-center">
             <div className="text-center">
                <h3 className="text-white text-xl font-black uppercase tracking-[0.2em]">{site.name}</h3>
                <p className="text-white/60 text-[11px] font-bold uppercase tracking-[0.3em] mt-2">
                  Image {activeImageIndex + 1} of {site.images.length}
                </p>
             </div>

             {/* Thumbnail Dots */}
             <div className="flex gap-3 mt-8">
               {site.images.map((_, i) => (
                 <button 
                  key={i} 
                  onClick={(e) => { e.stopPropagation(); setActiveImageIndex(i); }}
                  className={`h-1.5 rounded-full transition-all duration-300 ${activeImageIndex === i ? 'w-12 bg-red-600' : 'w-1.5 bg-white/30 hover:bg-white/60'}`}
                 />
               ))}
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default SiteDetailsPopup;

import React, { useState, useMemo, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import MapView from './components/MapView';
import { HeritageSite, SiteCategory } from './types';
import { parseHeritageData } from './utils/dataParser';
import { Layers, Home, Map as MapIcon, ChevronDown, Navigation, ArrowRight } from 'lucide-react';

const App: React.FC = () => {
  const allSites = useMemo(() => parseHeritageData(), []);

  const [showMap, setShowMap] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategories, setSelectedCategories] = useState<SiteCategory[]>(Object.values(SiteCategory));
  const [activeSite, setActiveSite] = useState<HeritageSite | null>(null);
  const [mapType, setMapType] = useState<'osm' | 'light' | 'satellite'>('light');
  const [showLayerSelect, setShowLayerSelect] = useState(false);
  const [locateMe, setLocateMe] = useState(0);

  const filteredSites = useMemo(() => {
    return allSites.filter(site => {
      const matchesSearch = site.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           site.location.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = site.categories.some(cat => selectedCategories.includes(cat));
      return matchesSearch && matchesCategory;
    });
  }, [allSites, searchTerm, selectedCategories]);

  const handleFilterToggle = useCallback((category: SiteCategory) => {
    setSelectedCategories(prev => 
      prev.includes(category) 
        ? prev.filter(c => c !== category) 
        : [...prev, category]
    );
  }, []);

  const handleSiteSelect = useCallback((site: HeritageSite) => {
    setActiveSite(site);
  }, []);

  const handleReset = useCallback(() => {
    setActiveSite(null);
    setSearchTerm('');
    setSelectedCategories(Object.values(SiteCategory));
  }, []);

  const layers = [
    { id: 'light', label: 'Light Canvas' },
    { id: 'osm', label: 'Street Map' },
    { id: 'satellite', label: 'Satellite View' }
  ];

  if (!showMap) {
    return (
      <div className="h-screen w-screen relative overflow-hidden bg-gray-900 flex flex-col items-center justify-center">
        <div className="absolute inset-0 z-0">
          <img 
            src="https://images.unsplash.com/photo-1544735716-392fe2489ffa?q=80&w=2071&auto=format&fit=crop" 
            className="w-full h-full object-cover opacity-30"
            alt="Heritage Background"
          />
          <div className="absolute inset-0 bg-gradient-to-b from-gray-900/40 via-gray-900/80 to-gray-900"></div>
        </div>

        <div className="relative z-10 flex flex-col items-center text-center px-6 max-w-4xl animate-in fade-in slide-in-from-bottom-8 duration-1000">
           <div className="mb-12 group cursor-default">
              {/* --- SPLASH LOGO: Increased size and refined zoom effect --- */}
              <div className="w-[420px] h-80 flex items-center justify-center transition-transform duration-700 group-hover:scale-110">
                <img 
                  src="./logo1.png" 
                  alt="Mappers Nepal Logo" 
                  className="w-full h-full object-contain drop-shadow-[0_0_50px_rgba(255,255,255,0.15)]"
                  onError={(e) => {
                    const target = e.currentTarget;
                    const parent = target.parentElement;
                    if (parent) {
                      target.style.display = 'none';
                      const label = document.createElement('span');
                      label.className = "text-6xl font-black text-white leading-none text-center tracking-tighter uppercase";
                      label.innerHTML = "MAPPERS<br/><span class='text-red-600'>NEPAL</span>";
                      parent.appendChild(label);
                    }
                  }}
                />
              </div>
           </div>

           <h1 className="text-6xl md:text-8xl font-black text-white uppercase tracking-tighter mb-4 leading-tight">
             Heritage Mapping <br/> <span className="text-red-600">in Nepal</span>
           </h1>

           <p className="text-gray-400 text-lg md:text-xl font-medium tracking-[0.2em] uppercase mb-12 max-w-2xl leading-relaxed">
             A Digital WebGIS Journey by Mappers Nepal
           </p>

           <button 
             onClick={() => setShowMap(true)}
             className="group relative flex items-center gap-4 bg-red-600 text-white px-14 py-6 text-sm font-black uppercase tracking-[0.4em] transition-all hover:bg-white hover:text-gray-900 shadow-[0_20px_50px_rgba(220,38,38,0.3)] hover:shadow-[0_20px_50px_rgba(255,255,255,0.2)]"
           >
             Launch Experience
             <ArrowRight size={20} className="group-hover:translate-x-2 transition-transform" />
           </button>

           <div className="mt-20 border-t border-white/10 pt-8 w-full">
              <p className="text-[10px] font-black text-white/40 uppercase tracking-[0.6em]">Digital Heritage Project &copy; 2024</p>
           </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen w-screen bg-white overflow-hidden">
      <header className="h-16 bg-white border-b border-gray-100 flex items-center justify-between px-8 shrink-0 z-[1001]">
        <div className="flex items-center gap-8">
          {/* --- HEADER LOGO: Removed box, integrated into horizontal flow --- */}
          <button 
            onClick={() => setShowMap(false)} 
            className="h-12 flex items-center justify-center transition-all hover:opacity-80 active:scale-95"
            title="Return to Splash Screen"
          >
            <img 
              src="./logo2.png" 
              alt="Mappers Nepal Logo" 
              className="h-full w-auto object-contain"
              onError={(e) => {
                const target = e.currentTarget;
                const parent = target.parentElement;
                if (parent) {
                  target.style.display = 'none';
                  const label = document.createElement('span');
                  label.className = "text-xl font-black text-red-600 tracking-tighter";
                  label.innerHTML = "MAPPERS NEPAL";
                  parent.appendChild(label);
                }
              }}
            />
          </button>

          <div className="flex items-center gap-4">
            <h1 className="text-xl font-black text-gray-900 tracking-tighter uppercase">Heritage Mapping Nepal</h1>
            <div className="h-4 w-px bg-gray-200 hidden md:block" />
            <p className="text-[10px] font-bold text-red-600 uppercase tracking-[0.4em] hidden md:block">Interactive WebGIS</p>
          </div>
        </div>

        <div className="flex items-center gap-2">
            <button 
              onClick={() => setLocateMe(prev => prev + 1)}
              className="h-9 px-4 bg-gray-50 border border-gray-100 flex items-center gap-2 hover:bg-red-50 hover:border-red-200 transition-all text-gray-600 hover:text-red-600"
              title="Find my location"
            >
              <Navigation size={14} />
              <span className="text-[8px] font-black uppercase tracking-widest hidden lg:block">Locate</span>
            </button>
            <button 
              onClick={handleReset}
              className="h-9 px-4 bg-gray-50 border border-gray-100 flex items-center gap-2 hover:bg-red-50 hover:border-red-200 transition-all text-gray-600 hover:text-red-600"
              title="Reset view to whole Nepal"
            >
              <Home size={14} />
              <span className="text-[8px] font-black uppercase tracking-widest hidden lg:block">Reset Map</span>
            </button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden relative">
        <Sidebar 
          sites={filteredSites}
          onSearch={setSearchTerm}
          onFilterToggle={handleFilterToggle}
          selectedCategories={selectedCategories}
          activeSiteId={activeSite?.id || null}
          onSiteClick={handleSiteSelect}
        />

        <main className="flex-1 relative bg-gray-50 overflow-hidden">
          <div className="absolute top-4 right-4 z-[1000]">
            <div className="relative">
              <button 
                onClick={() => setShowLayerSelect(!showLayerSelect)}
                className={`flex items-center justify-between gap-3 h-10 min-w-[180px] px-4 bg-white shadow-xl border border-gray-200 transition-all ${showLayerSelect ? 'border-red-600' : ''}`}
              >
                <div className="flex items-center gap-2">
                   <Layers size={14} className="text-gray-400" />
                   <span className="text-[8px] font-black text-gray-800 uppercase tracking-widest">
                     {layers.find(l => l.id === mapType)?.label}
                   </span>
                </div>
                <ChevronDown size={10} className={`text-gray-400 transition-transform ${showLayerSelect ? 'rotate-180' : ''}`} />
              </button>

              {showLayerSelect && (
                <div className="absolute right-0 mt-1 w-full bg-white shadow-2xl border border-gray-100 py-1">
                  {layers.map(layer => (
                    <button
                      key={layer.id}
                      onClick={() => { setMapType(layer.id as any); setShowLayerSelect(false); }}
                      className={`w-full text-left px-4 py-2 hover:bg-gray-50 flex flex-col border-l-4 transition-colors ${mapType === layer.id ? 'bg-red-50 border-red-600' : 'border-transparent'}`}
                    >
                      <span className={`text-[8px] font-black uppercase tracking-wider ${mapType === layer.id ? 'text-red-600' : 'text-gray-700'}`}>
                        {layer.label}
                      </span>
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>

          <MapView 
            sites={filteredSites} 
            activeSite={activeSite}
            onSiteSelect={handleSiteSelect}
            mapType={mapType}
            locateMe={locateMe}
          />
        </main>
      </div>
    </div>
  );
};

export default App;

